import React, { Suspense, lazy } from 'react';
import { MemoryRouter, Route, Routes, Navigate } from 'react-router-dom';
import { Provider } from 'react-redux';
import { ToastProvider } from '@linm-soft-org/linm-web-common-components';
import { store } from './store/store';
import { MemoryRouterSync } from './router/MemoryRouterSync';
import { ProtectedRoute } from './components/auth/ProtectedRoute';
import { showDevNav } from './dev/isStandalone';
import ShellUrlHomePage from './pages/ShellUrlHomePage/ShellUrlHomePage';

const DevPage = lazy(() => import('./dev/DevPageWrapper'));

const initialPath =
  typeof window !== 'undefined'
    ? window.location.pathname + window.location.search || '/'
    : '/';

const Root: React.FC = () => (
  <Provider store={store}>
    <ToastProvider>
      <MemoryRouter initialEntries={[initialPath]} initialIndex={0}>
        <MemoryRouterSync />
        <Routes>
          {showDevNav && (
            <>
              <Route path="/" element={<Navigate to="/dev" replace />} />
              <Route
                path="/dev"
                element={(
                  <Suspense fallback={null}>
                    <DevPage />
                  </Suspense>
                )}
              />
            </>
          )}

          <Route
            path="/shell/fm/*"
            element={(
              <ProtectedRoute>
                <ShellUrlHomePage />
              </ProtectedRoute>
            )}
          />
          <Route
            path="/shell-url/home"
            element={(
              <ProtectedRoute>
                <ShellUrlHomePage />
              </ProtectedRoute>
            )}
          />
          <Route path="/shell-url" element={<Navigate to="/shell-url/home" replace />} />
          <Route path="/shell-url/*" element={<Navigate to="/shell-url/home" replace />} />

          {!showDevNav && (
            <Route path="*" element={<Navigate to="/shell-url/home" replace />} />
          )}
          {showDevNav && (
            <Route path="*" element={<Navigate to="/dev" replace />} />
          )}
        </Routes>
      </MemoryRouter>
    </ToastProvider>
  </Provider>
);

export default Root;
